mapper.select:
			select  
					 sido
					,sigungu
					,dong
					,dangi

			from KR_REAL_INFO kri
			where 1=1

	            AND sido = #{sido}


            AND sigungu = #{sigungu}


            AND dong = #{dong}

        AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth}        
		group by sido, sigungu, dong, dangi

SELECT city ,bungi ,bonBun ,buBun ,dangi
,dediArea ,contYear ,contDate ,amount ,floor
,consYear ,road ,dateCancel ,transType ,brokerLoc
,regiDt ,sido ,sigungu ,dong FROM KR_REAL_INFO WHERE 1=1
AND sido = #{sido}
AND sigungu = #{sigungu}
AND dong = #{dong}
AND dangi = #{dangi}
AND ContYear BETWEEN #{startYearMonth} AND #{endYearMonth} ORDER BY city, bungi, BonBun
